const raw = $input.first().json.stdout;
const trends = JSON.parse(raw);
return trends.map(t => ({ json: t }));

const output = $input.first().json.stdout || '';
const lines = output.split('\n').filter(Boolean);
let uploaded = null;
for (const line of lines) {
  try {
    const parsed = JSON.parse(line);
    if (parsed.step === 'uploaded') uploaded = parsed;
  } catch {}
}
if (!uploaded) throw new Error('Upload failed: ' + output.slice(-200));
return [{ json: uploaded }];
